// // This module implements a 4-bit counter with an asynchronous reset. The counter decrements on every rising edge of the clock (clk) input and resets to 15 when the reset (areset) input is asserted. The module has an output (count) that is a 4-bit vector representing the current count value. Additionally, the module has an input (disable) that allows the counter to be enabled or disabled. When the disable input is high, the counter should not decrement and the count output should remain constant.
module counter (
  input clk,
  input areset,
  input enable,
  output reg [3:0] count
);

  always @(posedge clk) begin
    if (areset) begin
      count <= 4'b0;
    end
    else if (enable) begin
      count <= count + 1;
    end
  end

endmodule
